#include <iostream>
#include <cstring>
using namespace std;
int main()
{
    string s;
    int k,count=1;;
    cin>>k>>s;
    for(int i=0;i<=s.size()-1;i++)
    {
        if(s[i]==s[i+1])
        {
            count+=1;
            if(count==k)
            {
                cout<<s[i];
                return 0;
            }
        }
        else
        {
            count=1;
        }
    }
    cout<<"No";
    return 0;
}
